def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0 or item > capacity:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        score = 0
        if ratio < 0.2:
            score = np.exp(-5 * ratio) + np.cos(ratio * 10)
        elif 0.2 <= ratio < 0.5:
            score = np.log1p(ratio * 4) * 2 - np.sqrt(ratio) + np.sin(ratio * 3 * np.pi)
        elif 0.5 <= ratio < 0.8:
            score = 1 / (1 + np.exp(-20 * (ratio - 0.65))) + np.tanh(5 * (ratio - 0.7))
        else:
            score = np.tanh(15 * (ratio - 0.85)) + 0.7 + np.sin(ratio * 7)
        penalty = 0
        for j in range(1, 8):
            mod_val = (item * j) % capacity
            frac = mod_val / (capacity * j)
            if frac < 0.05:
                penalty += frac * 3
            elif 0.05 <= frac < 0.15:
                penalty += frac * 2
            elif 0.15 <= frac < 0.35:
                penalty += frac
            else:
                penalty += frac / (j + 2)
        extra_penalty = 0
        for k in range(1, 5):
            if ratio > (0.4 * k):
                extra_penalty += (np.exp(-k * ratio) * k * 1.2) + (np.cos(k * ratio * np.pi) * 0.5)
            else:
                extra_penalty += (np.log1p(k * ratio + 2) / (k + 2)) - (np.sin(k * ratio) * 0.3)
        adjustment = 0
        if capacity % 3 == 0:
            adjustment += np.sqrt(capacity) / (1 + ratio * 10)
        else:
            for m in range(1, 4):
                if m % 2 == 0:
                    adjustment += np.sin(capacity / (m + ratio + 1)) * 0.2
                else:
                    adjustment -= np.cos(capacity / (m + ratio + 1)) * 0.1
        if capacity % 2 == 0 and capacity % 3 == 0:
            priorities[i] = max(score + penalty * 0.9 + extra_penalty * 1.1 + adjustment, 0)
        elif capacity % 2 == 0:
            priorities[i] = max(score + penalty * 1.1 + extra_penalty * 0.9 + adjustment * 0.8, 0)
        elif capacity % 3 == 0:
            priorities[i] = max(score + penalty * 1.2 + extra_penalty * 0.8 + adjustment * 1.5, 0)
        else:
            priorities[i] = max(score + penalty * 1.3 + extra_penalty * 0.7 + adjustment, 0)
    return priorities
